@users_bp.route('/api/users/export.csv')
def export_users_csv():
    import csv
    import io
    from flask import Response

    def generate():
        buf = io.StringIO()
        writer = csv.writer(buf)
        writer.writerow(['id', 'username', 'email', 'created_at', 'status'])
        yield buf.getvalue()
        buf.seek(0)
        buf.truncate(0)
        for user in User.query.yield_per(500):
            writer.writerow([user.id, user.username, user.email, user.created_at.isoformat(), user.status])
            yield buf.getvalue()
            buf.seek(0)
            buf.truncate(0)

    return Response(
        generate(),
        mimetype='text/csv',
        headers={'Content-Disposition': 'attachment; filename=users.csv'}
    )
